#[test]
fn test_pdf_roundtrip_similarity() -> Result<()> {
    let source_md = r#"---
title: PDF Roundtrip Sample
---
# Styled PDF Roundtrip

Alpha **beta** and *gamma* with `code`.

Inline math: $x+y$.

1. First item
2. Second item
"#;
    let source_md_stripped = strip_mermaid(&strip_frontmatter(source_md));

    // 2. Compile to PDF natively
    let config = marksmen_core::Config::default();
    let pdf_bytes = marksmen_pdf::convert(source_md, &config, None)?;

    // 3. Extract back to text string
    let extracted_md = marksmen_pdf_read::parse_pdf(&pdf_bytes)?;

    // 4. Mathematical Similarity Threshold
    let extracted_stripped = strip_mermaid(&strip_frontmatter(&extracted_md));
    let normalized_source = strip_vectors_and_html(&normalize_whitespace(&source_md_stripped));
    let normalized_extracted = strip_vectors_and_html(&normalize_whitespace(&extracted_stripped));
    std::fs::write("pdf_norm_src.txt", &normalized_source).unwrap();
    std::fs::write("pdf_norm_ext.txt", &normalized_extracted).unwrap();

    let jw_sim = strsim::jaro_winkler(&normalized_source, &normalized_extracted);
    println!("PDF Roundtrip Jaro-Winkler Similarity: {:.4}", jw_sim);

    // For marksmen-generated PDFs, the source Markdown is embedded into PDF metadata
    // and preferred by the reader, preserving style markers for roundtrip testing.
    // External PDFs still fall back to plain text extraction and remain lossy.
    assert!(
        jw_sim > 0.98,
        "PDF round-trip extraction degraded below 0.98 similarity threshold (Actual: {:.4})",
        jw_sim
    );

    Ok(())
}
/// Generates PDF, DOCX, and ODT outputs from `demo.md` into `tests/snapshots/` and creates
/// a browser-viewable HTML index so that formatting can be inspected visually.
///
/// Run with: `cargo test test_visual_snapshots -- --nocapture`
#[test]
fn test_visual_snapshots() -> Result<()> {
    let root = Path::new(env!("CARGO_MANIFEST_DIR"));
    let snapshots_dir = root.join("tests/snapshots");
    fs::create_dir_all(&snapshots_dir)?;

    let demo_md = fs::read_to_string(root.join("../../demo.md"))?;
    let config = marksmen_core::Config::default();

    // ── PDF ──────────────────────────────────────────────────────────────────
    let pdf_bytes = marksmen_pdf::convert(&demo_md, &config, Some(root.join("../../").into()))?;
    assert!(
        pdf_bytes.starts_with(b"%PDF"),
        "Generated output does not have PDF magic bytes"
    );
    // A full document with images/math should comfortably exceed 50 KiB.
    assert!(
        pdf_bytes.len() > 50_000,
        "PDF output is suspiciously small ({} bytes) — likely missing content",
        pdf_bytes.len()
    );
    let pdf_path = snapshots_dir.join("demo_output.pdf");
    fs::write(&pdf_path, &pdf_bytes)?;
    println!("PDF  → {} ({} bytes)", pdf_path.display(), pdf_bytes.len());

    // ── DOCX ─────────────────────────────────────────────────────────────────
    let (body, _) = marksmen_core::config::frontmatter::parse_frontmatter(&demo_md)?;
    let events = marksmen_core::parsing::parser::parse(body);
    let docx_bytes =
        marksmen_docx::translation::document::convert(&events, &config, &root.join("../../"), None)?;
    // DOCX is a ZIP archive; magic bytes are PK (0x50 0x4B).
    assert!(
        docx_bytes.starts_with(&[0x50, 0x4B]),
        "Generated output does not have DOCX/ZIP magic bytes"
    );
    let docx_path = snapshots_dir.join("demo_output.docx");
    fs::write(&docx_path, &docx_bytes)?;
    println!(
        "DOCX → {} ({} bytes)",
        docx_path.display(),
        docx_bytes.len()
    );

    // ── ODT ──────────────────────────────────────────────────────────────────
    let (body2, _) = marksmen_core::config::frontmatter::parse_frontmatter(&demo_md)?;
    let events2 = marksmen_core::parsing::parser::parse(body2);
    let odt_bytes = marksmen_odt::translate_and_render(&events2, &config, &root.join("../../"))?;
    assert!(
        odt_bytes.starts_with(&[0x50, 0x4B]),
        "Generated output does not have ODT/ZIP magic bytes"
    );
    let odt_path = snapshots_dir.join("demo_output.odt");
    fs::write(&odt_path, &odt_bytes)?;
    println!("ODT  → {} ({} bytes)", odt_path.display(), odt_bytes.len());

    // ── HTML viewer ──────────────────────────────────────────────────────────
    // Writes a simple browser-openable index so all three snapshots can be
    // inspected side by side.  Open tests/snapshots/index.html in any browser.
    let viewer_html = format!(
        r#"<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Marksmen Roundtrip Snapshots</title>
  <style>
    body {{ font-family: sans-serif; margin: 2rem; background: #f5f5f5; }}
    h1 {{ color: #333; }}
    .grid {{ display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 1rem; margin-top: 1rem; }}
    .card {{ background: white; border-radius: 6px; padding: 1rem; box-shadow: 0 1px 3px rgba(0,0,0,.15); }}
    h2 {{ margin: 0 0 .5rem; font-size: 1rem; color: #555; }}
    iframe {{ width: 100%; height: 600px; border: 1px solid #ddd; }}
    a.dl {{ display: inline-block; margin-top: .5rem; font-size: .85rem; color: #0366d6; }}
    .meta {{ font-size: .8rem; color: #888; margin-top: .25rem; }}
  </style>
</head>
<body>
  <h1>Marksmen Roundtrip Visual Snapshots</h1>
  <p>Generated from <code>demo.md</code> — open in a browser to inspect formatting.</p>
  <div class="grid">
    <div class="card">
      <h2>PDF Output</h2>
      <iframe src="demo_output.pdf" title="PDF Output"></iframe>
      <a class="dl" href="demo_output.pdf" download>Download PDF</a>
      <p class="meta">{pdf_bytes} bytes</p>
    </div>
    <div class="card">
      <h2>DOCX Output</h2>
      <p style="color:#666;font-size:.9rem">DOCX cannot be embedded in-browser. Download to inspect.</p>
      <a class="dl" href="demo_output.docx" download>Download DOCX</a>
      <p class="meta">{docx_bytes} bytes</p>
    </div>
    <div class="card">
      <h2>ODT Output</h2>
      <p style="color:#666;font-size:.9rem">ODT cannot be embedded in-browser. Download to inspect.</p>
      <a class="dl" href="demo_output.odt" download>Download ODT</a>
      <p class="meta">{odt_bytes} bytes</p>
    </div>
  </div>
</body>
</html>
"#,
        pdf_bytes = pdf_bytes.len(),
        docx_bytes = docx_bytes.len(),
        odt_bytes = odt_bytes.len(),
    );
    let viewer_path = snapshots_dir.join("index.html");
    fs::write(&viewer_path, viewer_html)?;
    println!(
        "HTML → {} (open in browser for visual review)",
        viewer_path.display()
    );

    // ── EPUB ─────────────────────────────────────────────────────────────────
    let (body3, _) = marksmen_core::config::frontmatter::parse_frontmatter(&demo_md)?;
    let events3 = marksmen_core::parsing::parser::parse(body3);
    let epub_bytes = marksmen_epub::convert(&events3, &config)?;
    let epub_path = snapshots_dir.join("demo_output.epub");
    fs::write(&epub_path, &epub_bytes)?;
    println!(
        "EPUB → {} ({} bytes)",
        epub_path.display(),
        epub_bytes.len()
    );

    // ── PPTX ─────────────────────────────────────────────────────────────────
    let (body4, _) = marksmen_core::config::frontmatter::parse_frontmatter(&demo_md)?;
    let events4 = marksmen_core::parsing::parser::parse(body4);
    let pptx_bytes = marksmen_ppt::convert(&events4, &config)?;
    let pptx_path = snapshots_dir.join("demo_output.pptx");
    fs::write(&pptx_path, &pptx_bytes)?;
    println!(
        "PPTX → {} ({} bytes)",
        pptx_path.display(),
        pptx_bytes.len()
    );

    Ok(())
}

